698       Res.One |= Mask;
699       Res.Zero &= ~Mask;
700     } else {
701       Res.Zero |= Mask;
702       Res.One &= ~Mask;
703     }
704   }
705 
706   if (Overflow) {
707     // We know whether or not we overflowed.
708     if (!(*Overflow)) {
709       // No overflow.
710       return Res;
711     }
712 
713     // We overflowed
714     APInt C;
715     if (Signed) {
716       // sadd.sat / ssub.sat
717       assert(SignBitKnown(LHS) &&
718              "We somehow know overflow without knowing input sign");
