6004 Value *llvm::isBytewiseValue(Value *V, const DataLayout &DL) {
6005 
6006   // All byte-wide stores are splatable, even of arbitrary variables.
6007   if (V->getType()->isIntegerTy(8))
6008     return V;
6009 
6010   LLVMContext &Ctx = V->getContext();
6011 
6012   // Undef don't care.
6013   auto *UndefInt8 = UndefValue::get(Type::getInt8Ty(Ctx));
6014   if (isa<UndefValue>(V))
6015     return UndefInt8;
6016 
6017   // Return Undef for zero-sized type.
6018   if (DL.getTypeStoreSize(V->getType()).isZero())
6019     return UndefInt8;
6020 
6021   Constant *C = dyn_cast<Constant>(V);
6022   if (!C) {
6023     // Conceptually, we could handle things like:
6024     //   %a = zext i8 %X to i16
6025     //   %b = shl i16 %a, 8
6026     //   %c = or i16 %a, %b
6027     // but until there is an example that actually needs this, it doesn't seem
6028     // worth worrying about.
6029     return nullptr;
6030   }
6031 
6032   // Handle 'null' ConstantArrayZero etc.
6033   if (C->isNullValue())
6034     return Constant::getNullValue(Type::getInt8Ty(Ctx));
6035 
6036   // Constant floating-point values can be handled as integer values if the
6037   // corresponding integer value is "byteable".  An important case is 0.0.
6038   if (ConstantFP *CFP = dyn_cast<ConstantFP>(C)) {
6039     Type *Ty = nullptr;
6040     if (CFP->getType()->isHalfTy())
6041       Ty = Type::getInt16Ty(Ctx);
6042     else if (CFP->getType()->isFloatTy())
6043       Ty = Type::getInt32Ty(Ctx);
6044     else if (CFP->getType()->isDoubleTy())
6045       Ty = Type::getInt64Ty(Ctx);
6046     // Don't handle long double formats, which have strange constraints.
6047     return Ty ? isBytewiseValue(ConstantExpr::getBitCast(CFP, Ty), DL)
6048               : nullptr;
6049   }
6050 
6051   // We can handle constant integers that are multiple of 8 bits.
6052   if (ConstantInt *CI = dyn_cast<ConstantInt>(C)) {
6053     if (CI->getBitWidth() % 8 == 0) {
6054       assert(CI->getBitWidth() > 8 && "8 bits should be handled above!");
6055       if (!CI->getValue().isSplat(8))
6056         return nullptr;
6057       return ConstantInt::get(Ctx, CI->getValue().trunc(8));
6058     }
6059   }
6060 
6061   if (auto *CE = dyn_cast<ConstantExpr>(C)) {
6062     if (CE->getOpcode() == Instruction::IntToPtr) {
6063       if (auto *PtrTy = dyn_cast<PointerType>(CE->getType())) {
6064         unsigned BitWidth = DL.getPointerSizeInBits(PtrTy->getAddressSpace());
6065         if (Constant *Op = ConstantFoldIntegerCast(
6066                 CE->getOperand(0), Type::getIntNTy(Ctx, BitWidth), false, DL))
6067           return isBytewiseValue(Op, DL);
6068       }
6069     }
6070   }
6071 
6072   auto Merge = [&](Value *LHS, Value *RHS) -> Value * {
6073     if (LHS == RHS)
6074       return LHS;
6075     if (!LHS || !RHS)
6076       return nullptr;
6077     if (LHS == UndefInt8)
6078       return RHS;
6079     if (RHS == UndefInt8)
6080       return LHS;
6081     return nullptr;
6082   };
6083 
6084   if (ConstantDataSequential *CA = dyn_cast<ConstantDataSequential>(C)) {
6085     Value *Val = UndefInt8;
6086     for (unsigned I = 0, E = CA->getNumElements(); I != E; ++I)
6087       if (!(Val = Merge(Val, isBytewiseValue(CA->getElementAsConstant(I), DL))))
6088         return nullptr;
6089     return Val;
6090   }
6091 
6092   if (isa<ConstantAggregate>(C)) {
6093     Value *Val = UndefInt8;
6094     for (Value *Op : C->operands())
6095       if (!(Val = Merge(Val, isBytewiseValue(Op, DL))))
6096         return nullptr;
6097     return Val;
6098   }
6099 
6100   // Don't try to handle the handful of other constants.
6101   return nullptr;
6102 }
